import smolagents
from typing import Any, Dict

def detect_memory_drift(agent: smolagents.Agent, max_turns: int = 5) -> Dict[str, Any]:
    memory_snapshots = []
    critical_keys = {'user_prefs', 'intermediate_results', 'research_findings'}

    for i in range(max_turns):
        snapshot = {
            'turn': i,
            'memory_keys': set(agent.memory.keys()),
            'critical_missing': critical_keys - set(agent.memory.keys())
        }
        memory_snapshots.append(snapshot)

        if snapshot['critical_missing']:
            return {'drift_detected': True, 'missing_keys': snapshot['critical_missing'], 'turn': i}

    return {'drift_detected': False, 'snapshots': memory_snapshots}

from collections import defaultdict
import smolagents

def detect_redundant_calls(agent_history: list) -> list:
    tool_calls = []
    redundant = []

    for turn, messages in enumerate(agent_history):
        for msg in messages:
            if hasattr(msg, 'tool_calls'):
                for tool_call in msg.tool_calls:
                    tool_calls.append({
                        'turn': turn,
                        'name': tool_call['name'],
                        'params': tuple(sorted(tool_call['arguments'].items()))
                    })

    # Group identical calls
    call_groups = defaultdict(list)
    for call in tool_calls:
        key = (call['name'], call['params'])
        call_groups[key].append(call)

    for key, calls in call_groups.items():
        if len(calls) > 1:
            redundant.append({
                'tool': key[0],
                'params': key[1],
                'occurrences': calls
            })

    return redundant

