import smolagents
import json
from typing import Any, Dict, Optional

class PersistentAgent:
    def __init__(self, model: str, memory_file: str = 'agent_memory.json'):
        self.agent = smolagents.CodeAgent(model)
        self.memory_file = memory_file
        self.memory: Dict[str, Any] = self._load_memory()

    def _load_memory(self) -> Dict[str, Any]:
        try:
            with open(self.memory_file, 'r') as f:
                return json.load(f)
        except FileNotFoundError:
            return {}

    def _save_memory(self):
        with open(self.memory_file, 'w') as f:
            json.dump(self.memory, f, indent=2)

    def run(self, *args, **kwargs):
        # Inject memory into agent context
        self.agent.memory.update(self.memory)
        result = self.agent.run(*args, **kwargs)

        # Persist updated memory
        self.memory.update(self.agent.memory)
        self._save_memory()

        return result

# Usage
agent = PersistentAgent('gpt-4o-mini')
result = agent.run('Plan a trip to Tokyo')

import smolagents
from typing import List, Dict, Any

class CheckpointedAgent:
    def __init__(self, model: str):
        self.agent = smolagents.CodeAgent(model)
        self.checkpoints: Dict[str, Any] = {}

    def run_with_checkpoints(self, task: str, steps: List[str]):
        results = {}

        for i, step in enumerate(steps):
            checkpoint_key = f'step_{i}'
            context = self._build_context(task, results, i)

            prompt = f"""Task: {task}
Step {i+1}/{len(steps)}: {step}
Prior context: {context}

Respond with ONLY the result for this step."""

            result = self.agent.run(prompt)
            self.checkpoints[checkpoint_key] = {'step': step, 'result': result}
            results[f'step_{i}'] = result

        return {'final_result': results, 'checkpoints': self.checkpoints}

    def _build_context(self, task: str, results: Dict, current_step: int):
        context = []
        for i in range(max(0, current_step-2), current_step):
            if f'step_{i}' in results:
                context.append(f"Step {i+1}: {results[f'step_{i}']}")
        return '\n'.join(context)

# Usage
agent = CheckpointedAgent('gpt-4o-mini')
result = agent.run_with_checkpoints(
    'Build user profile',
    ['Extract preferences', 'Find recommendations', 'Generate summary']
)
